  if (!quickbooks_name) {
    process_state = false;
    issues.push("Missing 'Quickbooks Name'");
  }

   // 3. PER-ROW CHECK: Verify numeric values (Only evaluated if fields aren't empty)
  if (process_state) {
    const invalidNumericFields = [];
    for (const col of NUMERIC_CALC_COLUMNS) {
      if (isNaN(Number(String(raw[col]).trim()))) {
        invalidNumericFields.push(`[${col}] has non-numeric value "${raw[col]}"`);
      }
