    const devicePrice = parseFloat(raw["Monthly Device Per Patient Charge"] || 0);
    if (netBillableDevices > 0 && devicePrice > 0) {
      addLine(netBillableDevices * devicePrice, `Device Monitoring (${netBillableDevices} billable | ${freeDevicePatients} free)`, netBillableDevices, devicePrice, QB_ITEMS.DEVICES);
    }

    if (parseFloat(raw["AthenaHealth Integration Fee"]) > 0) addLine(raw["AthenaHealth Integration Fee"], "AthenaHealth Integration Fee", 1, raw["AthenaHealth Integration Fee"], QB_ITEMS.ATHENA_INTEGRATION);
    if (parseFloat(raw["Tebra Integration Fee"]) > 0) addLine(raw["Tebra Integration Fee"], "Tebra Integration Fee", 1, raw["Tebra Integration Fee"], QB_ITEMS.TEBRA_INTEGRATION);
    if (parseFloat(raw["Veradigm Integration Fee"]) > 0) addLine(raw["Veradigm Integration Fee"], "Veradigm Integration Fee", 1, raw["Veradigm Integration Fee"], QB_ITEMS.VERADIGM_INTEGRATION);

  } catch (err) {
    process_state = false;
    issues.push(`Logic Error: ${err.message}`);
  }
}
  if (process_state && lines.length === 0) {
    process_state = false;
    issues.push("No billable lines found for this record.");
  }

  // 3. After calculations, perform the Checksum
  const calculatedTotal = lines.reduce((sum, line) => sum + line.Amount, 0);
  const expectedTotal = parseFloat(raw["Total"] || 0);
