={{
  (() => {

    // ── STEP 1: GET ALL EXISTING INVOICES FROM QB ──────────────────
    // Fetches all invoices returned by the 'Get many invoices' node
    // Falls back to empty array if nothing returned
    const invoices = $('QB:Get Invoice').all() || [];

    // ── STEP 2: FIND THE HIGHEST EXISTING DOC NUMBER ───────────────
    // Loops through all invoices and extracts the trailing number
    // from each DocNumber (e.g. "TSTAD - 42" → 42)
    // reduce() keeps track of the highest number found
    const maxNumber = invoices.reduce((max, inv) => {
      // Match digits at the END of the DocNumber string
      // e.g. "TSTAD - 42" matches "42", "TESTAD - 5" matches "5"
      const match = inv.json?.DocNumber?.match(/(\d+)$/);
      // If a number was found, compare with current max and keep the bigger one
      return match ? Math.max(max, parseInt(match[1])) : max;
    }, 0); // Start from 0 so first invoice gets number 1

    // ── STEP 3: BUILD THE PREFIX FROM CUSTOMER NAME ────────────────
    // Customer name format expected: "TEST - Dr. John Smith"
    //                                 ^^^^   ^^^^ ^^^^ ^^^^^
    //                                 base   title first last

    // Get the customer name from current item's QB payload
    const name = $('Code:Check Process').item.json.quickbooks_payload?.CustomerRef?.name || '';

    // Split on '-' to separate base prefix from the name part
    // "TEST - Dr. John Smith" → ["TEST", "Dr. John Smith"]
    const parts = name.split('-').map(s => s.trim());

    const base = parts[0] || 'TEST';       // "TEST"

    // Split the name part into individual words
    // "Dr. John Smith" → ["Dr.", "John", "Smith"]
    // Then filter out "Dr" or "Dr." if it's the first word
    const words = (parts[1] || '').split(' ')
      .filter(Boolean) // Remove empty strings from extra spaces
      .filter((w, i) => i !== 0 || w.toLowerCase().replace('.', '') !== 'dr');
      // Only filters the FIRST word (i === 0), leaves rest untouched
      // "Dr. John Smith" → ["John", "Smith"]
      // "John Smith"     → ["John", "Smith"] (no change)

    // Build initials from the remaining words
    const initials = words.length >= 2
      ? words[0][0] + words[words.length - 1][0] // First + Last initial e.g. "JS"
      : words.length === 1 ? words[0][0]          // Only one word → single initial e.g. "J"
      : '';                                        // No words → no initials

    // ── STEP 4: BUILD FINAL DOC NUMBER ─────────────────────────────
    // Combines: base + initials + next sequential number
    // e.g. "TEST" + "JS" + " - " + 43 → "TESTJS - 43"
    return (base + initials.toUpperCase()) + ' - ' + (maxNumber + 1);

  })()
}}

