    job_id,
    customer_name,
    doc_number,
    status,
    error_message,
    raw_response,
    created_at
)
VALUES (
    '{{ $("Edit:Format Execution_id").first().json.job_id }}',
    '{{ ($json.CustomerRef?.name || "").replace(/'/g, "''") }}',
    '{{ $json.DocNumber || "" }}',
    'failed',
    '{{
  (() => {
    try {
      const desc = String($json.error?.description || '');
      // Extract JSON part after '400 - '
      const jsonPart = desc.replace(/^\d+\s*-\s*"/, '').replace(/"$/, '');
      // Unescape the string
      const unescaped = jsonPart.replace(/\\"/g, '"').replace(/\\\\/g, '\\');
      const parsed = JSON.parse(unescaped);
      const errors = parsed?.Fault?.Error || [];
      return errors.map(e => e.Detail || e.Message || '').join(' | ') || 'Unknown error';
    } catch(e) {
      return String($json.error?.message || 'Unknown error');
    }
  })()
}}',
    '{{ JSON.stringify({ status: "failed", error_code: String($json.error?.code || ""), error_message: String($json.error?.message || "No description") }).replace(/'/g, "''") }}',
    NOW()
);

